    },
    {
      "input": {
        "op": "stats_card",
        "stats": {
          "name": "Jane Doe",
          "totalStars": 100,
          "totalCommits": 200,
          "totalIssues": 300,
          "totalPRs": 400,
          "contributedTo": 500,
          "rank": {
            "level": "A+",
